'use strict';

/**
 * Sliding window rate limiting middleware for Express.
 *
 * This is a TRUE sliding window: it stores the timestamp of every request
 * per client and, on each new request, discards timestamps older than
 * `windowMs` before counting. There is no fixed interval that resets the
 * counter to zero, so a burst at the edge of a window cannot "double dip"
 * the way it can with a fixed-window counter.
 *
 * @param {Object}  [options]
 * @param {number}  [options.windowMs=60000]    Window size in milliseconds.
 * @param {number}  [options.maxRequests=100]   Max requests allowed per window.
 * @param {Function}[options.keyGenerator]      (req) => string. Defaults to req.ip.
 * @returns {Function} Express middleware with a `.close()` method attached.
 */
function createRateLimiter(options = {}) {
  const windowMs = options.windowMs != null ? options.windowMs : 60000;
  const maxRequests = options.maxRequests != null ? options.maxRequests : 100;
  const keyGenerator =
    typeof options.keyGenerator === 'function'
      ? options.keyGenerator
      : (req) => req.ip;

  // Map<clientKey, number[]>  — sorted-ascending arrays of request timestamps (ms).
  const hits = new Map();

  /**
   * Remove timestamps that fall outside the sliding window.
   * Because timestamps are appended in chronological order, all expired
   * entries are a contiguous prefix, so we can splice them in one shot.
   */
  function prune(timestamps, windowStart) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= windowStart) {
      i++;
    }
    if (i > 0) timestamps.splice(0, i);
    return timestamps;
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const windowStart = now - windowMs;
    const key = keyGenerator(req);

    let timestamps = hits.get(key);
    if (!timestamps) {
      timestamps = [];
      hits.set(key, timestamps);
    }

    // Drop everything older than the sliding window.
    prune(timestamps, windowStart);

    if (timestamps.length >= maxRequests) {
      // Over the limit. The window frees up when the OLDEST in-window request
      // ages out, i.e. oldestTimestamp + windowMs.
      const oldest = timestamps[0];
      const resetMs = oldest + windowMs;
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      res.set({
        'X-RateLimit-Limit': String(maxRequests),
        'X-RateLimit-Remaining': '0',
        'X-RateLimit-Reset': String(Math.ceil(resetMs / 1000)),
        'Retry-After': String(retryAfterSec),
      });

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next().
    }

    // Under the limit — record this request and allow it.
    timestamps.push(now);

    const remaining = maxRequests - timestamps.length;
    // Reset = when the oldest in-window request expires (when capacity
    // begins to free up).
    const resetMs = timestamps[0] + windowMs;

    res.set({
      'X-RateLimit-Limit': String(maxRequests),
      'X-RateLimit-Remaining': String(remaining),
      'X-RateLimit-Reset': String(Math.ceil(resetMs / 1000)),
    });

    next();
  };

  // ---- Memory management -------------------------------------------------
  // Periodically evict clients with no requests in the last windowMs so the
  // Map does not grow unbounded as IPs come and go.
  const cleanupTimer = setInterval(() => {
    const windowStart = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      prune(timestamps, windowStart);
      if (timestamps.length === 0) {
        hits.delete(key);
      }
    }
  }, 60000);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  /**
   * Stop the cleanup interval. Call this on graceful shutdown (or in tests)
   * so the timer is fully cleared and cannot keep the event loop running.
   */
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  return middleware;
}

module.exports = createRateLimiter;
module.exports.createRateLimiter = createRateLimiter;
