```js
/**
 * slidingWindowRateLimiter.js
 *
 * True sliding-window rate limiting middleware for Express.js.
 *
 * Unlike a fixed-window approach (which resets a counter every N seconds and
 * allows a burst of `maxRequests` at the end of one window immediately
 * followed by another burst at the start of the next), this implementation
 * stores every request timestamp and re-evaluates the window from "now" on
 * every single request.
 *
 * PROXY NOTE ──────────────────────────────────────────────────────────────────
 * `req.ip` is used as the client identifier. Behind a reverse proxy (Nginx,
 * AWS ALB, Cloudflare, etc.) Express will see the proxy's IP — not the real
 * client IP — UNLESS you enable the trust proxy setting:
 *
 *   app.set('trust proxy', 1);  // trust the first hop (most common setup)
 *
 * With trust proxy on, Express reads `X-Forwarded-For` and sets `req.ip` to
 * the leftmost (originating client) address. Without it, every request looks
 * like it comes from the same IP, making rate limiting effectively global
 * rather than per-client. See: https://expressjs.com/en/guide/behind-proxies.html
 * ─────────────────────────────────────────────────────────────────────────────
 */

'use strict';

/**
 * Factory that creates a sliding-window rate-limiter middleware.
 *
 * @param {object} [options]
 * @param {number} [options.windowMs=60000]    Rolling window size in ms.
 * @param {number} [options.maxRequests=100]   Max requests allowed per window.
 *
 * @returns {{ middleware: Function, close: Function }}
 *   - `middleware` — Express middleware `(req, res, next) => void`
 *   - `close()`    — Clears the background cleanup timer; call on shutdown
 *                    or in test teardown so the process can exit cleanly.
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000;  // default: 1 minute
  const maxRequests = options.maxRequests ?? 100;

  if (typeof windowMs !== 'number' || windowMs <= 0) {
    throw new TypeError('options.windowMs must be a positive number');
  }
  if (typeof maxRequests !== 'number' || maxRequests <= 0) {
    throw new TypeError('options.maxRequests must be a positive number');
  }

  /**
   * Per-IP timestamp store.
   * Maps an IP string → chronologically-ordered array of request timestamps (ms).
   * Only timestamps within the current window are retained.
   *
   * @type {Map<string, number[]>}
   */
  const store = new Map();

  // ── Background cleanup ────────────────────────────────────────────────────
  // Every 60 s, evict any IP whose newest request is older than windowMs.
  // Prevents unbounded memory growth for services that see many unique IPs.
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [ip, timestamps] of store) {
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] <= cutoff) {
        store.delete(ip);
      }
    }
  }, 60_000);

  // Allow the process to exit even if this interval is still scheduled.
  if (cleanupInterval.unref) {
    cleanupInterval.unref();
  }

  // ── Middleware ─────────────────────────────────────────────────────────────
  function middleware(req, res, next) {
    const ip  = req.ip || req.connection?.remoteAddress || 'unknown';
    const now = Date.now();
    const windowStart = now - windowMs;   // oldest timestamp still "in-window"

    // 1. Retrieve or initialise the timestamp list for this IP.
    let timestamps = store.get(ip);
    if (!timestamps) {
      timestamps = [];
      store.set(ip, timestamps);
    }

    // 2. Slide the window: discard every timestamp that has aged out.
    //    Timestamps are always appended in chronological order, so stale
    //    entries are always at the front — one splice pass is enough.
    let staleCount = 0;
    while (staleCount < timestamps.length && timestamps[staleCount] <= windowStart) {
      staleCount++;
    }
    if (staleCount > 0) timestamps.splice(0, staleCount);

    const currentCount = timestamps.length;

    // 3a. REJECTED — at or over limit.
    if (currentCount >= maxRequests) {
      // The oldest remaining timestamp tells us the earliest moment another
      // request can succeed (once it slides out of the window).
      const retryAfterMs  = timestamps[0] + windowMs - now;
      const retryAfterSec = Math.ceil(retryAfterMs / 1000);

      res.set('Retry-After', String(retryAfterSec));

      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
    }

    // 3b. ALLOWED — record this request, set informational headers, continue.
    timestamps.push(now);

    // Reset = the moment the oldest in-window request ages out.
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.set('X-RateLimit-Limit',     String(maxRequests));
    res.set('X-RateLimit-Remaining', String(maxRequests - timestamps.length));
    res.set('X-RateLimit-Reset',     String(resetEpochSec));

    next();
  }

  /** Stop the background cleanup timer. */
  function close() {
    clearInterval(cleanupInterval);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
