const { createRateLimiter } = require('./slidingWindowRateLimiter');

const app = express();

// ⚠️  Required when Express sits behind Nginx, a load balancer, etc.
app.set('trust proxy', 1);

// 50 requests per 30-second rolling window, per IP.
const { middleware: apiLimiter, close: closeApiLimiter } = createRateLimiter({
  windowMs:    30_000,
  maxRequests: 50,
});

// Apply globally:
app.use(apiLimiter);

// — or — only on specific route prefixes:
// app.use('/api/', apiLimiter);

app.get('/', (req, res) => res.json({ ok: true }));

